INSERT INTO dbo.DM_TBL_SRG_TACTICAL_AUDIT (Tactical_Audit_ID, Activity_Code, Track_ID, Tail_ID, Composite_Risk_Score, Intelligence_Summary, Action_1, Action_2, Action_3, data_last_updated, dm_refresh_date) VALUES
('TACT-RI-001','Runway Incursion','OPS-RI-001','9V-761',25,'No direct investigation or surveillance notes were linked to track TGW598. General runway-incursion exposure remains driven by vehicle crossing risk, low-speed taxi confusion, and radio discipline gaps seen across recent occurrence records.','Reconfirm runway access control and escort procedure for all ground vehicles.','Issue targeted radio phraseology reminder to tug and maintenance crews.','Review hold-point signage and low-visibility taxi brief for current shift.','2026-04-22 09:15:00','2026-04-22 09:15:00'),
('TACT-BS-001','Bird Strike','OPS-BS-002','9V-JAS',22,'Bird-strike exposure is concentrated on approach and climb-out corridors with repeated windshield and engine-ingestion subtypes. Wildlife dispersal timing and turnaround inspection discipline remain the main mitigations.','Synchronise wildlife dispersal patrols with the morning arrival bank.','Brief line inspectors to prioritise radome, windshield, and fan-blade checks after reports.','Track repeat subtypes by location to separate random strikes from persistent habitat issues.','2026-04-22 09:15:00','2026-04-22 09:15:00');
